import{_ as c,C as h,o as i,c as u,a2 as o,b as r,w as n,a as e,E as l,a3 as d,j as t}from"./chunks/framework.B72_uj9U.js";const P=JSON.parse('{"title":"Capy — Agentic Loop","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/capy/agentic-loop.md","filePath":"research/agents/capy/agentic-loop.md"}'),p={name:"research/agents/capy/agentic-loop.md"};function g(m,a,b,f,k,C){const s=h("Mermaid");return i(),u("div",null,[a[2]||(a[2]=o('<h1 id="capy-—-agentic-loop" tabindex="-1">Capy — Agentic Loop <a class="header-anchor" href="#capy-—-agentic-loop" aria-label="Permalink to &quot;Capy — Agentic Loop&quot;">​</a></h1><blockquote><p>Three-phase handoff: User describes task → Captain explores and specs → Build executes autonomously.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Unlike most coding agents that run a single agentic loop (prompt → tool call → observe → repeat), Capy structures its workflow as a <strong>three-phase handoff</strong> between the user, Captain (planning agent), and Build (execution agent). Each phase has distinct responsibilities and hard capability constraints.</p><h2 id="the-three-phase-handoff" tabindex="-1">The Three-Phase Handoff <a class="header-anchor" href="#the-three-phase-handoff" aria-label="Permalink to &quot;The Three-Phase Handoff&quot;">​</a></h2><h3 id="phase-1-user-describes-task" tabindex="-1">Phase 1: User Describes Task <a class="header-anchor" href="#phase-1-user-describes-task" aria-label="Permalink to &quot;Phase 1: User Describes Task&quot;">​</a></h3><p>The user creates a new task (or &quot;jam&quot;) in the Capy IDE and describes what they want:</p><ul><li>Natural language description of the feature, bug fix, refactor, etc.</li><li>Can reference existing GitHub issues</li><li>Can tag teammates for collaboration</li><li>The task becomes the organizing unit — it groups the chat, branch, environment, and eventual PR</li></ul><h3 id="phase-2-captain-plans" tabindex="-1">Phase 2: Captain Plans <a class="header-anchor" href="#phase-2-captain-plans" aria-label="Permalink to &quot;Phase 2: Captain Plans&quot;">​</a></h3><p>Captain activates as the <strong>planning agent</strong>:</p><ol><li><strong>Codebase Exploration</strong>: Captain reads the relevant parts of the codebase to understand the current architecture, patterns, and conventions</li><li><strong>Clarification Loop</strong>: If the task description is ambiguous, Captain <strong>asks the user clarifying questions</strong>. This is a key capability — Captain can have a back-and-forth dialogue with the user to fully understand requirements</li><li><strong>Research</strong>: Captain can research documentation, explore dependencies, and understand the broader context</li><li><strong>Spec Writing</strong>: Captain produces an exhaustive specification — described as &quot;a short PRD&quot; (Product Requirements Document) — that fully describes what Build should implement</li></ol><p><strong>Hard constraints on Captain:</strong></p><ul><li>Cannot write production code</li><li>Cannot run terminal commands</li><li>Cannot push commits</li><li>Must produce a spec as its sole output</li></ul><p>The clarification loop is critical: because Build <strong>cannot</strong> ask questions once it starts, Captain must resolve all ambiguities upfront. This creates a natural quality gate — if Captain doesn&#39;t ask the right questions, Build may implement the wrong thing.</p><h3 id="phase-3-build-executes" tabindex="-1">Phase 3: Build Executes <a class="header-anchor" href="#phase-3-build-executes" aria-label="Permalink to &quot;Phase 3: Build Executes&quot;">​</a></h3><p>Build activates as the <strong>execution agent</strong>, receiving:</p><ul><li>The spec from Captain</li><li>Access to the codebase (via its own git worktree)</li><li>A full Ubuntu VM with sudo access</li></ul><p>Build then works <strong>autonomously and asynchronously</strong>:</p><ol><li><strong>Reads the spec</strong> to understand what to implement</li><li><strong>Edits files</strong> according to the specification</li><li><strong>Installs dependencies</strong> as needed</li><li><strong>Runs tests</strong> to verify the implementation</li><li><strong>Opens a pull request</strong> on GitHub when complete</li></ol><p><strong>Hard constraints on Build:</strong></p><ul><li>Cannot ask the user clarifying questions mid-task</li><li>Must make judgment calls on any remaining ambiguities</li><li>Works fully asynchronously — user can close the browser and come back later</li></ul><h2 id="feedback-mechanisms" tabindex="-1">Feedback Mechanisms <a class="header-anchor" href="#feedback-mechanisms" aria-label="Permalink to &quot;Feedback Mechanisms&quot;">​</a></h2><h3 id="during-captain-phase" tabindex="-1">During Captain Phase <a class="header-anchor" href="#during-captain-phase" aria-label="Permalink to &quot;During Captain Phase&quot;">​</a></h3><p>The feedback loop is <strong>synchronous and interactive</strong>:</p>',24)),(i(),r(d,null,{default:n(()=>[l(s,{id:"mermaid-183",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20User%0A%20%20%20%20participant%20Captain%0A%20%20%20%20Captain-%3E%3EUser%3A%20%22What%20auth%20provider%3F%22%0A%20%20%20%20User-%3E%3ECaptain%3A%20%22Use%20OAuth2%20with%20Google%22%0A%20%20%20%20Captain-%3E%3EUser%3A%20%22Here's%20the%20spec...%22%0A"})]),fallback:n(()=>[...a[0]||(a[0]=[e(" Loading... ",-1)])]),_:1})),a[3]||(a[3]=t("p",null,"Captain can ask multiple rounds of clarifying questions before producing the final spec.",-1)),a[4]||(a[4]=t("h3",{id:"during-build-phase",tabindex:"-1"},[e("During Build Phase "),t("a",{class:"header-anchor",href:"#during-build-phase","aria-label":'Permalink to "During Build Phase"'},"​")],-1)),a[5]||(a[5]=t("p",null,[e("The feedback loop is "),t("strong",null,"asynchronous and one-directional"),e(":")],-1)),(i(),r(d,null,{default:n(()=>[l(s,{id:"mermaid-193",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20Build%20--%3E%20C%5B%22Code%20Changes%22%5D%20--%3E%20Tests%20--%3E%20PR%5B%22Pull%20Request%22%5D%0A%20%20%20%20Build%20-.%20%22User%20monitors%20in%20Capy%20dashboard%5Cn(cannot%20intervene%20mid-execution)%22%20.-%3E%20PR%0A"})]),fallback:n(()=>[...a[1]||(a[1]=[e(" Loading... ",-1)])]),_:1})),a[6]||(a[6]=o('<p>If Build&#39;s output is unsatisfactory, the user creates a <strong>new task</strong> with feedback, potentially triggering another Captain → Build cycle. This is more like a code review loop than an interactive debugging session.</p><h3 id="parallel-task-management" tabindex="-1">Parallel Task Management <a class="header-anchor" href="#parallel-task-management" aria-label="Permalink to &quot;Parallel Task Management&quot;">​</a></h3><p>Because each task runs independently:</p><ul><li>User can launch multiple Captain → Build pipelines simultaneously</li><li>Tasks don&#39;t block each other</li><li>The Capy dashboard shows all active tasks and their status</li><li>Up to 25 concurrent jams on the Pro plan</li></ul><h2 id="comparison-to-single-agent-loops" tabindex="-1">Comparison to Single-Agent Loops <a class="header-anchor" href="#comparison-to-single-agent-loops" aria-label="Permalink to &quot;Comparison to Single-Agent Loops&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Single-Agent (e.g., Claude Code)</th><th>Capy Captain/Build</th></tr></thead><tbody><tr><td>Planning</td><td>Same agent plans and codes</td><td>Dedicated planning agent</td></tr><tr><td>Clarification</td><td>Can ask anytime during execution</td><td>Only during planning phase</td></tr><tr><td>Execution</td><td>Interactive, user monitors</td><td>Autonomous, asynchronous</td></tr><tr><td>Iteration</td><td>Edit-test loop within one session</td><td>New task for each iteration</td></tr><tr><td>Parallelism</td><td>One task at a time (typically)</td><td>Up to 25 concurrent tasks</td></tr></tbody></table><h2 id="limitations-of-this-analysis" tabindex="-1">Limitations of This Analysis <a class="header-anchor" href="#limitations-of-this-analysis" aria-label="Permalink to &quot;Limitations of This Analysis&quot;">​</a></h2><p>The internal details of how Captain explores codebases, how specs are structured, and how Build&#39;s execution loop works internally are not publicly documented. The above is reconstructed from Capy&#39;s blog posts and marketing materials.</p>',8))])}const q=c(p,[["render",g]]);export{P as __pageData,q as default};
